function minSpeedOnTime(dist, hour) {
    let max_time = hour - dist.length + 1;
    let lower = 1.0, upper = 1e7;
    while (upper - lower >= 1e-9) {
        let mid = (lower + upper) / 2;
        let time_taken = 0.0;
        for (let i = 0; i < dist.length; ++i) {
            time_taken += Math.ceil(dist[i] / mid) - (i == dist.length - 1 ? 0 : 1);
        }
        if (time_taken <= max_time) {
            upper = mid;
        } else {
            lower = mid;
        }
    }
    return (lower <= 1e7) ? Math.ceil(lower) : -1;
}
```

    The algorithm uses a binary search to find the minimum train speed that enables reaching the office on time. We start with the range [1, 1e7] and calculate the midpoint of the range as a candidate train speed. We then check if, at that speed, the total time taken to reach the office, including waiting times between trains, is less than or equal to the allowed hour. To calculate the total time taken, we sum the time taken for each train ride and the waiting time for each train except the last one. If the total time is within the allowed hour, we update the upper bound; otherwise, we update the lower bound. We continue until the difference between upper and lower is smaller than 1e-9. Finally, we return the ceiling of the lower bound as the minimum speed, or -1 if it equals or exceeds 1e7.

